const hoje = new Date();

return $input.all()
  .map(item => {
    const lead = item.json;
    const historico = lead.historico_resumido || '';
    const ref = new Date(lead.updated_at || lead.created_at);
    const dias = Math.floor((hoje - ref) / (1000 * 60 * 60 * 24));

    const jaEnviou = (d) => historico.includes(`[D${d}]`);

    let etapa = null;
    let dia = null;

    // Sem nenhum follow-up enviado ainda: usa timing original desde abordagem
    if (!jaEnviou(2) && !jaEnviou(3) && !jaEnviou(5) && !jaEnviou(6) && !jaEnviou(7)) {
      if (dias === 2)                        { etapa = 'D2'; dia = 2; }
      else if (dias === 3)                   { etapa = 'D3'; dia = 3; }
      else if (dias >= 5 && dias <= 6)       { etapa = 'D5'; dia = 5; }
    }
    // Com follow-ups parciais: usa updated_at como referência relativa
    else if (jaEnviou(2) && !jaEnviou(3))   { if (dias >= 1) { etapa = 'D3'; dia = 3; } }
    else if (jaEnviou(3) && !jaEnviou(5))   { if (dias >= 2) { etapa = 'D5'; dia = 5; } }
    else if (jaEnviou(5) && !jaEnviou(6))   { if (dias >= 1) { etapa = 'D6'; dia = 6; } }
    else if (jaEnviou(6) && !jaEnviou(7))   { if (dias >= 1) { etapa = 'D7'; dia = 7; } }

    return {
      json: {
        lead_id: lead.id,
        nome: lead.nome_fantasia || lead.nome,
        dono: lead.dono ? lead.dono.split(' ')[0] : null,
        segmento: lead.segmento || '',
        cidade: lead.cidade || '',
        whatsapp_numero: lead.whatsapp_numero,
        resultado_alvo: lead.resultado_alvo || '',
        historico_resumido: lead.historico_resumido || '',
        dias,
        dia,
        etapa,
        encerrar: etapa === 'D7',
        precisa_followup: etapa !== null
      }
    };
  })
  .filter(item => item.json.precisa_followup);

const lead = $input.first().json;

const contexto = `Gere o follow-up para o seguinte lead:\n- Negocio: ${lead.nome || 'o negocio'}\n- Dono (primeiro nome): ${lead.dono || 'nao identificado'}\n- Segmento: ${lead.segmento || 'nao informado'}\n- Cidade: ${lead.cidade || 'nao informada'}\n- Resultado que buscam: ${lead.resultado_alvo || 'resultados no negocio'}\n- Dia do follow-up: ${lead.dia}\n- Historico do que ja foi enviado: ${lead.historico_resumido || 'abordagem inicial enviada, sem detalhe disponivel'}`;

return [{
  json: {
    lead_id: lead.lead_id,
    lead_nome: lead.nome,
    dono: lead.dono,
    segmento: lead.segmento,
    cidade: lead.cidade,
    resultado_alvo: lead.resultado_alvo,
    historico_resumido: lead.historico_resumido,
    dia: lead.dia,
    etapa: lead.etapa,
    encerrar: lead.encerrar,
    whatsapp_numero: lead.whatsapp_numero,
    contexto_lead: contexto
  }
}];

const agentOutput = $input.first().json.output || '';
const whatsapp = $('Preparar Contexto FU').first().json.whatsapp_numero;

const partes = agentOutput.split(/\\\\/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

return partes.map(mensagem => ({ json: { mensagem, whatsapp_numero: whatsapp } }));

if ($itemIndex > 0) {
  await new Promise(r => setTimeout(r, 2000));
}
return $input.item;
